    anchors.top: name.bottom
    margin-top: 6
    height: 20
    font: verdana-11px-rounded
    text: Add Player

CustomList < Panel
  size: 220 225
  padding: 6
  padding-top: 4
  image-source: /images/ui/window
  image-border: 6

  ToolTipLabel
    id: title
    anchors.horizontalCenter: parent.horizontalCenter
    anchors.top: parent.top
    text: Custom Players
    tooltip: Custom players are always eligible and use the global healing percentages.

  PlayerList
    id: playerList
    anchors.top: title.bottom
    margin-top: 6
    anchors.left: parent.left
    anchors.right: parent.right

  HorizontalSeparator
    anchors.top: playerList.bottom
    margin-top: 6
    anchors.left: parent.left
    anchors.right: parent.right

  AddPlayer
    id: addPanel
    anchors.top: prev.bottom
    margin-top: 5
    anchors.left: parent.left
    anchors.right: parent.right
    anchors.bottom: parent.bottom

Conditions < Panel
  size: 320 470
  padding: 6
  padding-top: 4
  image-source: /images/ui/window
  image-border: 6

  ToolTipLabel
    id: title
    anchors.horizontalCenter: parent.horizontalCenter
    anchors.top: parent.top
    text: Items and Healing Conditions

  Panel
    id: box
    anchors.top: title.bottom
    margin-top: 7
    anchors.left: parent.left
    anchors.right: parent.right
    anchors.bottom: parent.bottom
    padding: 3
    layout:
      type: grid
      cell-size: 300 43
      cell-spacing: 6
      num-columns: 1

FriendHealer < MainWindow
  !text: tr('Friend Healer')
  size: 570 705
  padding-top: 30
  @onEscape: self:hide()

  Priority
    id: priority
    anchors.top: parent.top
    anchors.left: parent.left

  CustomList
    id: customList
    anchors.top: priority.bottom
    margin-top: 10
    anchors.left: priority.left

  Conditions
    id: conditions
    anchors.top: parent.top
    anchors.right: parent.right

  TargetSettings
    id: targetSettings
    anchors.top: conditions.bottom
    margin-top: 10
    anchors.right: conditions.right

  HorizontalSeparator
    id: separator
    anchors.right: parent.right
    anchors.left: parent.left
    anchors.bottom: closeButton.top
    margin-bottom: 8

  BotSwitch
    id: sCheckRL
    !text: tr('Check RL Conditions')
    anchors.left: parent.left
    anchors.verticalCenter: closeButton.verticalCenter
    size: 145 20
    font: verdana-11px-rounded

  Button
    id: closeButton
    !text: tr('Close')
    font: cipsoftFont
    anchors.right: parent.right
    anchors.bottom: parent.bottom
    size: 60 21
    @onClick: self:getParent():hide()
]]
