-- Custom by F.Almeida
local offsetDirections = {
  [North]      =  {0,-1},
  [East]       =  {1,0},
  [South]      =  {0,1},
  [West]       =  {-1,0},
  [NorthEast]  =  {-1,-1},
  [SouthEast]  =  {-1,1},
  [SouthWest]  =  {1,1},
  [NorthWest]  =  {1,-1},
}
function Creature.getNextPosition(self,offset,ignoreDiagonal)
  local nextDir = self:getDirection()
  if ignoreDiagonal and nextDir > 3 then
    if table.find({NorthEast,SouthEast},nextDir) then
      nextDir = East
    else
      nextDir = West
    end
  end
  offset = offset or 1
  local off = offsetDirections[nextDir]
  local pos = self:getPosition()
  pos.x, pos.y = pos.x + (off[1] * offset), pos.y + (off[2] * offset)
  return pos
end

function Creature.getNextTile(self,offset,ignoreDiagonal)
  local nextPos = self:getNextPosition(offset,ignoreDiagonal)
  return g_map.getTile(nextPos)
end

function getTilesInRange(distance,position,ignoreBelow)
  local t = {}
  local d = distance or 2
  local pos = position or pos()
  for x = -d,d do
    for y = -d,d do
      if not ignoreBelow or x ~= 0 or y ~= 0 then
        local tile = g_map.getTile({x=pos.x+x,y=pos.y+y,z=pos.z})
        if tile then
          table.insert(t,tile)
        end
      end
    end
  end
  return t
end

function findItemOnGroundInRange(id,range,position,ignoreBelow)
  local pos = position or pos()
  for i, tile in ipairs(getTilesInRange(range,pos,ignoreBelow)) do
    for j, item in ipairs(tile:getItems()) do
      if item:getId() == id then return item end
    end
  end
end]=]
FILES["vBot/zenith_mobile_ui.lua"] = [[
-- Zenith Mobile floating interface.
-- Redirects the legacy bot tab helpers to an independent floating window.

local root = g_ui.getRootWidget()

storage.zenithMobileUI = storage.zenithMobileUI or {}
local uiStorage = storage.zenithMobileUI
if uiStorage.open == nil then
  uiStorage.open = true
end

local OPEN_BUTTON_IMAGE = '/bot/Zenith Mobile/images/zenith_open.png'
local CLOSE_BUTTON_IMAGE = '/bot/Zenith Mobile/images/zenith_close.png'

local window = g_ui.createWidget('ZenithMobileWindow', root)
window.botWidget = true
window:hide()

local toggleButton = g_ui.createWidget('ZenithMobileToggleButton', root)
toggleButton.botWidget = true

local tabBar = window.zenithTabs
local tabContent = window.zenithTabContent
tabBar:setContentWidget(tabContent)

local currentPanel = nil
local tabPanels = {}

local function normalizeTabName(name)
  name = tostring(name or 'Main')
  local lowered = name:lower()

  if lowered == 'hp' then
    return 'HP'
  elseif lowered == 'cave' then
    return 'Cave'
  elseif lowered == 'target' then
    return 'Target'
  elseif lowered == 'tools' then
    return 'Tools'
  elseif lowered == 'main' then
    return 'Main'
  end

  return name
end

local function updateToggleAppearance()
  -- Red ZENITH opens the window; the silver CLOSE artwork closes it.
  toggleButton:setText('')
  toggleButton:setImageSource(window:isVisible() and CLOSE_BUTTON_IMAGE or OPEN_BUTTON_IMAGE)
  toggleButton:setImageColor('#ffffff')
  toggleButton:setOpacity(1.0)
end

local function showWindow()
  window:show()
  window:raise()
  window:focus()
  uiStorage.open = true
  updateToggleAppearance()
end

local function hideWindow()
  window:hide()
  uiStorage.open = false
  updateToggleAppearance()
end

local function toggleWindow()
  if window:isVisible() then
    hideWindow()
  else
    showWindow()
  end
end

local function createTab(name)
  name = normalizeTabName(name)

  if tabPanels[name] then
    return tabPanels[name]
  end

  local existing = tabBar:getTab(name)
  if existing and existing.tabPanel and existing.tabPanel.content then
    tabPanels[name] = existing.tabPanel.content
    return tabPanels[name]
  end

  local botPanel = g_ui.createWidget('BotPanel')
  botPanel.botWidget = true
  botPanel:setId('zenithMobile' .. name:gsub('[^%w]', '') .. 'Tab')

  local tab = tabBar:addTab(name, botPanel)
  tabBar:setOn(true)

  if #tabBar.tabs >= 5 then
    for _, tabButton in pairs(tabBar.tabs) do
      tabButton:setFont('small-9px')
    end
  end

  tabPanels[name] = tab.tabPanel.content
  return tabPanels[name]
end

-- Replace the bot's legacy tab routing with the floating Zenith window.
addTab = function(name)
  return createTab(name)
end

getTab = addTab

setDefaultTab = function(name)
  currentPanel = createTab(name)
  panel = currentPanel
  return currentPanel
end

setupUI = function(otml, parent)
  parent = parent or currentPanel or panel or createTab('Main')
  local widget = g_ui.loadUIFromString(otml, parent)
  widget.botWidget = true
  return widget
end

createWidget = function(name, parent)
  parent = parent or currentPanel or panel or createTab('Main')
  local widget = g_ui.createWidget(name, parent)
  widget.botWidget = true
  return widget
end

addSwitch = function(id, text, callback, parent)
  local widget = createWidget('BotSwitch', parent)
  widget:setId(id)
  widget:setText(text)
  widget.onClick = callback
  return widget
end

addButton = function(id, text, callback, parent)
  local widget = createWidget('BotButton', parent)
  widget:setId(id)
  widget:setText(text)
  widget.onClick = callback
  return widget
end

addLabel = function(id, text, parent)
  local widget = createWidget('BotLabel', parent)
  widget:setId(id)
  widget:setText(text)
  return widget
end

addTextEdit = function(id, text, callback, parent)
  local widget = createWidget('BotTextEdit', parent)
  widget:setId(id)
  widget:setText(text)
  widget.onTextChange = callback
  return widget
end

addSeparator = function(id, parent)
  local widget = createWidget('BotSeparator', parent)
  widget:setId(id)
  return widget
end

-- Modern UI helpers also default to the floating tab currently selected by scripts.
UI.createWidget = function(name, parent)
  parent = parent or currentPanel or panel or createTab('Main')
  local widget = g_ui.createWidget(name, parent)
  widget.botWidget = true
  return widget
end

-- Make built-in helpers that depend on context.panel follow our window.
local firstPanel = createTab('Cave')
currentPanel = firstPanel
panel = firstPanel
mainTab = firstPanel
tabs = tabBar

window.closeButton.onClick = hideWindow
window.onEscape = hideWindow
toggleButton.onClick = toggleWindow

-- Keep the floating window usable on both desktop and smaller mobile layouts.
local rootWidth = root:getWidth()
local rootHeight = root:getHeight()
window:setWidth(math.min(430, math.max(240, rootWidth - 20)))
window:setHeight(math.min(560, math.max(300, rootHeight - 40)))
local windowWidth = window:getWidth()
local windowHeight = window:getHeight()
window:setPosition({
  x = math.max(0, math.floor((rootWidth - windowWidth) / 2)),
  y = math.max(0, math.floor((rootHeight - windowHeight) / 2))
})

-- Locate the client's native TG and ATK controls and put Zenith directly
-- below the pair. The search accepts both visible labels and common widget ids.
local function safeText(widget)
  local ok, value = pcall(function() return widget:getText() end)
  if not ok or value == nil then return '' end
  return tostring(value):gsub('^%s+', ''):gsub('%s+$', ''):upper()
end

local function safeId(widget)
  local ok, value = pcall(function() return widget:getId() end)
  if not ok or value == nil then return '' end
  return tostring(value):lower()
end

local function safeRect(widget)
  local ok, rect = pcall(function() return widget:getRect() end)
  if ok and rect and rect.x and rect.y and rect.width and rect.height then
    return rect
  end

  local okPos, pos = pcall(function() return widget:getPosition() end)
  if not okPos or not pos then return nil end
  return {
    x = pos.x,
    y = pos.y,
    width = widget:getWidth(),
    height = widget:getHeight(),
  }
end

local function isUsableNativeWidget(widget)
  if widget == toggleButton or widget.botWidget then return false end
  local visible = true
  pcall(function() visible = widget:isVisible() end)
  if not visible then return false end

  local rect = safeRect(widget)
  if not rect or rect.width < 18 or rect.height < 12 then return false end
  if rect.width > 220 or rect.height > 100 then return false end
  if rect.x > root:getWidth() * 0.42 or rect.y > root:getHeight() * 0.42 then return false end
  return true
end

local function expandToControl(widget)
  local selected = widget
  local childRect = safeRect(widget)

  for _ = 1, 3 do
    local ok, parent = pcall(function() return selected:getParent() end)
    if not ok or not parent or parent == root or parent.botWidget then break end

    local rect = safeRect(parent)
    if not rect or rect.width > 180 or rect.height > 52 then break end
    if childRect and (rect.width < childRect.width or rect.height < childRect.height) then break end

    selected = parent
    childRect = rect
  end

  return selected, safeRect(selected)
end

local function classifyNativeControl(widget)
  if not isUsableNativeWidget(widget) then return nil end

  local text = safeText(widget)
  local id = safeId(widget)

  if text == 'TG' or id == 'tg' or id:find('targeting', 1, true) or id:find('targetbutton', 1, true) or id:find('target_button', 1, true) then
    return 'TG', text == 'TG' and 0 or 30
  end

  if text == 'ATK' or id == 'atk' or id:find('caster', 1, true) or id:find('attackbutton', 1, true) or id:find('attack_button', 1, true) then
    return 'ATK', text == 'ATK' and 0 or 30
  end

  return nil
end

local function findNativeControls(widget, found)
  found = found or {}

  local kind, penalty = classifyNativeControl(widget)
  if kind then
    local control, rect = expandToControl(widget)
    local score = rect.y * 3 + rect.x + penalty
    if not found[kind] or score < found[kind].score then
      found[kind] = { widget = control, rect = rect, score = score }
    end
  end

  local ok, children = pcall(function() return widget:getChildren() end)
  if ok and children then
    for _, child in ipairs(children) do
      findNativeControls(child, found)
    end
  end

  return found
end

local function findStoreWidget(widget, best)
  if widget ~= toggleButton and isUsableNativeWidget(widget) and safeText(widget) == 'STORE' then
    local control, rect = expandToControl(widget)
    local score = rect.y * 3 + rect.x
    if not best or score < best.score then
      best = { widget = control, rect = rect, score = score }
    end
  end

  local ok, children = pcall(function() return widget:getChildren() end)
  if ok and children then
    for _, child in ipairs(children) do
      best = findStoreWidget(child, best)
    end
  end
  return best
end

local function applyToggleGeometry(x, y, width)
  width = math.max(116, math.min(148, width or 126))
  local height = math.max(36, math.floor(width * 0.325))

  toggleButton:breakAnchors()
  toggleButton:setWidth(width)
  toggleButton:setHeight(height)
  toggleButton:setPosition({ x = math.floor(x), y = math.floor(y) })
  toggleButton:raise()
end

local function placeToggleButton()
  local controls = findNativeControls(root)
  local tg = controls.TG
  local atk = controls.ATK

  if tg and atk then
    local left = math.min(tg.rect.x, atk.rect.x)
    local right = math.max(tg.rect.x + tg.rect.width, atk.rect.x + atk.rect.width)
    local bottom = math.max(tg.rect.y + tg.rect.height, atk.rect.y + atk.rect.height)
    applyToggleGeometry(left, bottom + 4, right - left)
    return true
  end

  -- STORE is part of the same fixed mobile block. It is a reliable fallback
  -- on custom clients whose TG/ATK labels are painted instead of real text.
  local store = findStoreWidget(root, nil)
  if store then
    local width = math.max(116, math.min(148, store.rect.width))
    applyToggleGeometry(store.rect.x, store.rect.y + store.rect.height + 78, width)
    return true
  end

  -- Last-resort position matching the stock mobile layout: directly below
  -- the TG/ATK row, never in the middle of the game screen.
  applyToggleGeometry(6, math.max(148, math.floor(root:getHeight() * 0.215)), 126)
  return false
end

local function retryTogglePlacement(remaining)
  placeToggleButton()
  if remaining <= 0 then return end
  schedule(300, function() retryTogglePlacement(remaining - 1) end)
end

retryTogglePlacement(30)

local previousRootGeometry = root.onGeometryChange
root.onGeometryChange = function(widget, oldRect, newRect)
  if previousRootGeometry then
    pcall(previousRootGeometry, widget, oldRect, newRect)
  end
  schedule(50, placeToggleButton)
end

-- Zenith Mobile is hosted entirely by its own floating runtime.

if uiStorage.open then
  showWindow()
else
  hideWindow()
end

ZenithMobileUI = {
  window = window,
  button = toggleButton,
  show = showWindow,
  hide = hideWindow,
  toggle = toggleWindow,
  getTab = createTab,
}
]]
