    if panelId == 1 then
      context.storage[panelName].item1 = 3052
      context.storage[panelName].item2 = 3089
      context.storage[panelName].slot = 9
    end
  end

  ui.title:setText("Auto equip")
  ui.title:setOn(context.storage[panelName].enabled)
